def describe(**facts):
    for key in facts:
        print(key, "->", facts[key])

describe(name="Sam", age=11, pet="dog")

def smallest_and_largest(numbers):
    return min(numbers), max(numbers)

low, high = smallest_and_largest([4, 9, 1, 7])
print("Smallest:", low)
print("Largest:", high)

blocks.solution:
def product(*nums):
    result = 1
    for n in nums:
        result *= n
    return result

print(product(2, 3, 4))

challenge.solution:
def make_profile(name, greeting="Hello", **details):
    print(greeting + ",", name + "!")
    for key in details:
        print(key + ":", details[key])

make_profile("Sam", greeting="Hi", age=11, city="Austin")
